import{_ as t,o as r,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"20. Transition To Retirement","description":"","frontmatter":{"title":"20. Transition To Retirement","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["employment","flexible-work","preliminary"]},"headers":[],"relativePath":"ebas/mspp/employment/20-transition-to-retirement.md","filePath":"ebas/mspp/employment/20-transition-to-retirement.md"}'),n={name:"ebas/mspp/employment/20-transition-to-retirement.md"};function i(s,e,p,l,h,m){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_20-transition-to-retirement" tabindex="-1">20. Transition To Retirement <a class="header-anchor" href="#_20-transition-to-retirement" aria-label="Permalink to &quot;20. Transition To Retirement&quot;">​</a></h1><p>Note: A retirement transition arrangement is not notice to resign employment.</p><p><strong>20.1</strong> An Employee may advise their Employer in writing of their intention to retire within the next five years and participate in a retirement transition arrangement.</p><p><strong>20.2</strong> Transition to retirement arrangements may be proposed and, where agreed, implemented:</p><p><strong>a.</strong> as a flexible working arrangement (see <a href="/eba/ebas/mspp/employment/27-flexible-working-arrangements.html">clause 27</a> (Requests for Flexible Working Arrangements)), or</p><p><strong>b.</strong> as an individual flexibility arrangement (see <a href="/eba/ebas/mspp/employment/22-individual-flexibility-arrangements.html">clause 22</a> (Individual Flexibility Arrangement)); or</p><p><strong>c.</strong> in writing between the parties, or</p><p><strong>d.</strong> any combination of the above.</p><p><strong>20.3</strong> A transition to retirement arrangement may include but is not limited to:</p><p><strong>a.</strong> a reduction of working hours, i.e. part time employment;</p><p><strong>b.</strong> a job share arrangement;</p><p><strong>c.</strong> working in a position at a lower classification or rate of pay;</p><p><strong>d.</strong> flexible use of Long Service Leave (LSL).</p><p><strong>20.4</strong> The Employer will consider, and not unreasonably refuse, a request by an Employee who wishes to transition to retirement:</p><p><strong>a.</strong> to use accrued LSL or Annual Leave for the purpose of reducing the number of days worked per week while retaining their previous employment status;</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p>Examples: 1. A full-time Employee may work 3 days per week and have 2 days of accrued long service leave per week, retaining their full-time status until they have exhausted their available long service leave credits. 2. A part-time Employee employed for 24 hours per week may work 20 hours per week and take 4 hours of accrued annual leave per week until they have exhausted their available annual leave credits, retaining their status as a part-time Employee employed for 24 hours per week for that period of time. or</p><p><strong>b.</strong> be appointed to a role which that has a lower hourly rate of pay or hours (post transition role), in which case:</p><p><strong>(i)</strong> the Employer will preserve the accrual of LSL at the time of reduction in salary or hours; and</p><p><strong>(ii)</strong> where LSL is taken or paid out in lieu on termination, the Employee will be paid LSL hours at the applicable classification, and at the preserved hours, prior to the post transition role until the preserved LSL hours are exhausted unless: <strong>(A)</strong> if the Employee’s hourly wage rate in the post transition role over time exceeds the wage rate of the pre-transition role, the higher wage rate will be used to calculate LSL. Examples:</p><ol><li><p>An Employee’s hourly rate of pay is reduced under this subclause 20.4b from $35 to $30. When the Employee takes LSL their LSL will be paid at the rate of $35 per hour until the preserved LSL is exhausted.</p></li><li><p>An Employee’s hours of work are reduced under this subclause 20.4b from 32 hours per week to 24 hours per week. When the Employee takes LSL they will be paid for 32 hours of LSL per week until the preserved LSL is exhausted.</p></li><li><p>An Employee’s hourly rate of pay is reduced under this subclause 20.4b from $40 to $35 and their hours of work from 38 to 30 hours per week. When the Employee takes LSL it will be paid at the rate of $40 per hour and they will be paid for 38 hours of LSL per week until the preserved LSL is exhausted.</p></li></ol><p>Plain language terms: phased retirement, winding down, TTR.</p>',22)])])}const g=t(n,[["render",i]]);export{d as __pageData,g as default};
